// lib/models/user_model.dart
import 'dart:convert';

class UserModel {
  final String id;
  final String email;
  final String displayName;
  final String? avatarUrl;
  final Map<String, dynamic>? metadata;

  UserModel({
    required this.id,
    required this.email,
    required this.displayName,
    this.avatarUrl,
    this.metadata,
  });

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'email': email,
      'displayName': displayName,
      'avatarUrl': avatarUrl,
      'metadata': metadata,
    };
  }

  factory UserModel.fromJson(Map<String, dynamic> json) {
    return UserModel(
      id: json['id'] as String,
      email: json['email'] as String,
      displayName: json['displayName'] as String,
      avatarUrl: json['avatarUrl'] as String?,
      metadata: json['metadata'] as Map<String, dynamic>?,
    );
  }

  String toJsonString() => jsonEncode(toJson());

  factory UserModel.fromJsonString(String jsonString) {
    return UserModel.fromJson(jsonDecode(jsonString) as Map<String, dynamic>);
  }

  UserModel copyWith({
    String? id,
    String? email,
    String? displayName,
    String? avatarUrl,
    Map<String, dynamic>? metadata,
  }) {
    return UserModel(
      id: id ?? this.id,
      email: email ?? this.email,
      displayName: displayName ?? this.displayName,
      avatarUrl: avatarUrl ?? this.avatarUrl,
      metadata: metadata ?? this.metadata,
    );
  }

  @override
  String toString() =>
      'UserModel(id: $id, email: $email, displayName: $displayName)';
}

// lib/models/auth_tokens.dart
class AuthTokens {
  final String accessToken;
  final String refreshToken;
  final DateTime expiresAt;

  AuthTokens({
    required this.accessToken,
    required this.refreshToken,
    required this.expiresAt,
  });

  bool get isExpired => DateTime.now().isAfter(expiresAt);

  bool get isAboutToExpire =>
      DateTime.now().isAfter(expiresAt.subtract(const Duration(minutes: 5)));

  Map<String, dynamic> toJson() {
    return {
      'accessToken': accessToken,
      'refreshToken': refreshToken,
      'expiresAt': expiresAt.toIso8601String(),
    };
  }

  factory AuthTokens.fromJson(Map<String, dynamic> json) {
    return AuthTokens(
      accessToken: json['accessToken'] as String,
      refreshToken: json['refreshToken'] as String,
      expiresAt: DateTime.parse(json['expiresAt'] as String),
    );
  }
}

// lib/services/auth_storage_service.dart
import 'dart:convert';
import 'package:shared_preferences/shared_preferences.dart';

class AuthStorageService {
  static const String _accessTokenKey = 'auth_access_token';
  static const String _refreshTokenKey = 'auth_refresh_token';
  static const String _tokenExpiryKey = 'auth_token_expiry';
  static const String _userDataKey = 'auth_user_data';
  static const String _isLoggedInKey = 'auth_is_logged_in';
  static const String _lastLoginKey = 'auth_last_login';
  static const String _rememberMeKey = 'auth_remember_me';

  SharedPreferences? _prefs;

  Future<SharedPreferences> get prefs async {
    _prefs ??= await SharedPreferences.getInstance();
    return _prefs!;
  }

  // Save auth tokens
  Future<void> saveTokens(AuthTokens tokens) async {
    final sp = await prefs;
    await Future.wait([
      sp.setString(_accessTokenKey, tokens.accessToken),
      sp.setString(_refreshTokenKey, tokens.refreshToken),
      sp.setString(_tokenExpiryKey, tokens.expiresAt.toIso8601String()),
    ]);
  }

  // Retrieve auth tokens
  Future<AuthTokens?> getTokens() async {
    final sp = await prefs;
    final accessToken = sp.getString(_accessTokenKey);
    final refreshToken = sp.getString(_refreshTokenKey);
    final expiryString = sp.getString(_tokenExpiryKey);

    if (accessToken == null || refreshToken == null || expiryString == null) {
      return null;
    }

    return AuthTokens(
      accessToken: accessToken,
      refreshToken: refreshToken,
      expiresAt: DateTime.parse(expiryString),
    );
  }

  // Save user data
  Future<void> saveUser(UserModel user) async {
    final sp = await prefs;
    await sp.setString(_userDataKey, user.toJsonString());
  }

  // Retrieve user data
  Future<UserModel?> getUser() async {
    final sp = await prefs;
    final userJson = sp.getString(_userDataKey);
    if (userJson == null) return null;
    try {
      return UserModel.fromJsonString(userJson);
    } catch (_) {
      return null;
    }
  }

  // Save login state
  Future<void> setLoggedIn(bool value) async {
    final sp = await prefs;
    await sp.setBool(_isLoggedInKey, value);
    if (value) {
      await sp.setString(_lastLoginKey, DateTime.now().toIso8601String());
    }
  }

  Future<bool> isLoggedIn() async {
    final sp = await prefs;
    return sp.getBool(_isLoggedInKey) ?? false;
  }

  Future<DateTime?> getLastLoginTime() async {
    final sp = await prefs;
    final lastLogin = sp.getString(_lastLoginKey);
    if (lastLogin == null) return null;
    return DateTime.parse(lastLogin);
  }

  // Remember me preference
  Future<void> setRememberMe(bool value) async {
    final sp = await prefs;
    await sp.setBool(_rememberMeKey, value);
  }

  Future<bool> getRememberMe() async {
    final sp = await prefs;
    return sp.getBool(_rememberMeKey) ?? false;
  }

  // Clear all auth data
  Future<void> clearAll() async {
    final sp = await prefs;
    await Future.wait([
      sp.remove(_accessTokenKey),
      sp.remove(_refreshTokenKey),
      sp.remove(_tokenExpiryKey),
      sp.remove(_userDataKey),
      sp.remove(_isLoggedInKey),
      sp.remove(_lastLoginKey),
    ]);
  }
}

