// lib/managers/auth_manager.dart
import 'dart:async';
import 'package:flutter/foundation.dart';

enum AuthState {
  initial,
  loading,
  authenticated,
  unauthenticated,
  error,
}

class AuthManager extends ChangeNotifier {
  final AuthStorageService _storage;
  final AuthApiService _api;

  AuthState _state = AuthState.initial;
  UserModel? _currentUser;
  AuthTokens? _currentTokens;
  String? _errorMessage;
  Timer? _tokenRefreshTimer;

  AuthManager({
    AuthStorageService? storage,
    AuthApiService? api,
  })  : _storage = storage ?? AuthStorageService(),
        _api = api ?? AuthApiService();

  // Getters
  AuthState get state => _state;
  UserModel? get currentUser => _currentUser;
  AuthTokens? get currentTokens => _currentTokens;
  String? get errorMessage => _errorMessage;
  bool get isAuthenticated => _state == AuthState.authenticated;
  bool get isLoading => _state == AuthState.loading;

  // Initialize - check for existing session
  Future<void> initialize() async {
    _setState(AuthState.loading);

    try {
      final isLoggedIn = await _storage.isLoggedIn();
      if (!isLoggedIn) {
        _setState(AuthState.unauthenticated);
        return;
      }

      final tokens = await _storage.getTokens();
      final user = await _storage.getUser();

      if (tokens == null || user == null) {
        await _storage.clearAll();
        _setState(AuthState.unauthenticated);
        return;
      }

      // Check if tokens are expired
      if (tokens.isExpired) {
        // Try to refresh
        try {
          await _refreshTokens(tokens.refreshToken);
          _currentUser = user;
          _startTokenRefreshTimer();
          _setState(AuthState.authenticated);
        } catch (_) {
          await _storage.clearAll();
          _setState(AuthState.unauthenticated);
        }
      } else {
        _currentTokens = tokens;
        _currentUser = user;
        _startTokenRefreshTimer();
        _setState(AuthState.authenticated);
      }
    } catch (e) {
      _errorMessage = 'Failed to restore session: $e';
      _setState(AuthState.error);
    }
  }

  // Login
  Future<bool> login({
    required String email,
    required String password,
    bool rememberMe = true,
  }) async {
    _setState(AuthState.loading);
    _errorMessage = null;

    try {
      final response = await _api.login(email, password);

      final user = UserModel.fromJson(response['user'] as Map<String, dynamic>);
      final tokens =
          AuthTokens.fromJson(response['tokens'] as Map<String, dynamic>);

      // Persist session
      await _persistSession(user, tokens, rememberMe);

      _currentUser = user;
      _currentTokens = tokens;
      _startTokenRefreshTimer();
      _setState(AuthState.authenticated);

      return true;
    } on AuthException catch (e) {
      _errorMessage = e.message;
      _setState(AuthState.error);
      return false;
    } catch (e) {
      _errorMessage = 'An unexpected error occurred. Please try again.';
      _setState(AuthState.error);
      return false;
    }
  }

  // Register
  Future<bool> register({
    required String email,
    required String password,
    required String displayName,
  }) async {
    _setState(AuthState.loading);
    _errorMessage = null;

    try {
      final response = await _api.register(email, password, displayName);

      final user = UserModel.fromJson(response['user'] as Map<String, dynamic>);
      final tokens =
          AuthTokens.fromJson(response['tokens'] as Map<String, dynamic>);

      await _persistSession(user, tokens, true);

      _currentUser = user;
      _currentTokens = tokens;
      _startTokenRefreshTimer();
      _setState(AuthState.authenticated);

      return true;
    } on AuthException catch (e) {
      _errorMessage = e.message;
      _setState(AuthState.error);
      return false;
    } catch (e) {
      _errorMessage = 'Registration failed. Please try again.';
      _setState(AuthState.error);
      return false;
    }
  }

  // Logout
  Future<void> logout() async {
    _setState(AuthState.loading);

    try {
      if (_currentTokens != null) {
        await _api.logout(_currentTokens!.accessToken);
      }
    } catch (_) {
      // Continue with local logout even if API call fails
    }

    _stopTokenRefreshTimer();
    await _storage.clearAll();
    _currentUser = null;
    _currentTokens = null;
    _errorMessage = null;
    _setState(AuthState.unauthenticated);
  }

  // Update user profile locally
  Future<void> updateUserProfile(UserModel updatedUser) async {
    _currentUser = updatedUser;
    await _storage.saveUser(updatedUser);
    notifyListeners();
  }

  // Get valid access token (refreshes if needed)
  Future<String?> getValidAccessToken() async {
    if (_currentTokens == null) return null;

    if (_currentTokens!.isAboutToExpire) {
      try {
        await _refreshTokens(_currentTokens!.refreshToken);
      } catch (_) {
        await logout();
        return null;
      }
    }

    return _currentTokens?.accessToken;
  }

  // Private methods

  Future<void> _persistSession(
      UserModel user, AuthTokens tokens, bool rememberMe) async {
    await Future.wait([
      _storage.saveUser(user),
      _storage.saveTokens(tokens),
      _storage.setLoggedIn(true),
      _storage.setRememberMe(rememberMe),
    ]);
  }

  Future<void> _refreshTokens(String refreshToken) async {
    final response = await _api.refreshToken(refreshToken);
    final newTokens = AuthTokens.fromJson(response);

    _currentTokens = newTokens;
    await _storage.saveTokens(newTokens);
  }

  void _startTokenRefreshTimer() {
    _stopTokenRefreshTimer();

    if (_currentTokens == null) return;

    // Schedule refresh 5 minutes before expiry
    final timeUntilRefresh = _currentTokens!.expiresAt
        .subtract(const Duration(minutes: 5))
        .difference(DateTime.now());

    if (timeUntilRefresh.isNegative) {
      // Token is about to expire or already expired, refresh now
      _refreshTokens(_currentTokens!.refreshToken).catchError((_) {
        logout();
      });
      return;
    }

    _tokenRefreshTimer = Timer(timeUntilRefresh, () async {
      try {
        await _refreshTokens(_currentTokens!.refreshToken);
        _startTokenRefreshTimer(); // Restart timer for next refresh
      } catch (_) {
        await logout();
      }
    });
  }

  void _stopTokenRefreshTimer() {
    _tokenRefreshTimer?.cancel();
    _tokenRefreshTimer = null;
  }

  void _setState(AuthState newState) {
    _state = newState;
    notifyListeners();
  }

  @override
  void dispose() {
    _stopTokenRefreshTimer();
    super.dispose();
  }
}

